qry:select.qry:xquery:
					for $r in sql('
maxsize 1001
SELECT 
T.oi_posicion, 
P.c_puesto, 
P.d_puesto, 
T.c_posicion, 
T.d_posicion
FROM 
ORG04_PUESTOS as P,
ORG04_POSICIONES as T                     
JOIN
P.oi_puesto INNER T.oi_puesto      
WHERE
P.oi_empresa={#SOURCE:@empresa}
{%?(#SOURCE:@search1!='') {% AND ( contain(ucase(P.c_puesto), {upper-case(#SOURCE:@search1)}) or contain(ucase(P.d_puesto), {upper-case(#SOURCE:@search1)}) OR contain(ucase(T.c_posicion), {upper-case(#SOURCE:@search1)}) or contain(ucase(T.d_posicion), {upper-case(#SOURCE:@search1)}) %} {% %} %} 
{%?(#SOURCE:@search2!='') {% OR contain(ucase(P.c_puesto), {upper-case(#SOURCE:@search2)}) or contain(ucase(P.d_puesto), {upper-case(#SOURCE:@search2)}) OR contain(ucase(T.c_posicion), {upper-case(#SOURCE:@search2)}) or contain(ucase(T.d_posicion), {upper-case(#SOURCE:@search2)}) %} {% %} %} 
{%?(#SOURCE:@search3!='') {% OR contain(ucase(P.c_puesto), {upper-case(#SOURCE:@search3)}) or contain(ucase(P.d_puesto), {upper-case(#SOURCE:@search3)}) OR contain(ucase(T.c_posicion), {upper-case(#SOURCE:@search3)}) or contain(ucase(T.d_posicion), {upper-case(#SOURCE:@search3)}) %} {% %} %}
{%?(#SOURCE:@search4!='') {% OR contain(ucase(P.c_puesto), {upper-case(#SOURCE:@search4)}) or contain(ucase(P.d_puesto), {upper-case(#SOURCE:@search4)}) OR contain(ucase(T.c_posicion), {upper-case(#SOURCE:@search4)}) or contain(ucase(T.d_posicion), {upper-case(#SOURCE:@search4)}) %} {% %} %} 
{%?(#SOURCE:@search5!='') {% OR contain(ucase(P.c_puesto), {upper-case(#SOURCE:@search5)}) or contain(ucase(P.d_puesto), {upper-case(#SOURCE:@search5)}) OR contain(ucase(T.c_posicion), {upper-case(#SOURCE:@search5)}) or contain(ucase(T.d_posicion), {upper-case(#SOURCE:@search5)}) %} {% %} %} 
{%?(#SOURCE:@search1!='') {% ) %} {% %} %} 
')/ROWS/ROW
